#include <bits/stdc++.h>
using namespace std;

const int N=5e5+10;

int n,m,f[N][20],dep[N];
vector<int> g[N];

void dfs(int x,int fa){
    dep[x]=dep[fa]+1;
    for(int y:g[x])
        if(y!=fa){
            f[y][0]=x;
            for(int i=1;f[f[y][i-1]][i-1];i++)
                f[y][i]=f[f[y][i-1]][i-1];
            dfs(y,x);
        }
}

int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=19;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    if(x==y)
        return x;
    for(int i=19;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];
    return f[x][0];
}

int dis(int x,int y){
    int lca=LCA(x,y);
    return dep[x]+dep[y]-2*dep[lca];
}

int cal(int x,int y,int z){
    int a=LCA(x,y),b=LCA(x,z),c=LCA(y,z);
    return (dep[a]>dep[b] && dep[a]>dep[c]?a:(dep[b]>dep[c]?b:c));
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    dfs(1,0);
    while(m--){
        int x,y,z;
        scanf("%d%d%d",&x,&y,&z);
        int p=cal(x,y,z);
        printf("%d %d\n",p,dis(x,p)+dis(y,p)+dis(z,p));
    }
    return 0;
}
